kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr int32_t SCALAR_BUF_NUM = 2;

class KernelSoftmaxCustom {
public:
    __aicore__ inline KernelSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t blockDim, uint32_t rowLength)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        rowLen_ = rowLength;
        numRows_ = totalLen_ / rowLen_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));        // for exp/sub
        pipe_.InitBuffer(scalarQueue_, SCALAR_BUF_NUM, sizeof(float));  // for scalar results
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0 || rowLen_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());

        // Each block processes a contiguous set of rows.
        const uint32_t rowsPerBlock = (numRows_ + blockNum - 1) / blockNum;
        const uint32_t startRow = blockIdx * rowsPerBlock;
        const uint32_t endRow = (startRow + rowsPerBlock > numRows_) ? numRows_ : startRow + rowsPerBlock;

        for (uint32_t rowIdx = startRow; rowIdx < endRow; ++rowIdx) {
            processRow(rowIdx);
        }
    }

private:
    // Phase 1: Find the maximum value along the row.
    __aicore__ inline float phase1FindMax(uint32_t rowOffset, uint32_t numTiles)
    {
        const float NEG_INF = -1e38f;
        float globalMax = NEG_INF;
        for (uint32_t t = 0; t < numTiles; ++t) {
            const uint32_t tileBase = rowOffset + t * tileLen_;
            const uint32_t curLen = (tileLen_ > (rowLen_ - t * tileLen_)) ? (rowLen_ - t * tileLen_) : tileLen_;
            if (curLen == 0) break;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[tileBase], curLen);

            AscendC::LocalTensor<float> maxScalar = scalarQueue_.AllocTensor<float>();
            AscendC::ReduceMax(maxScalar, xLocal, AscendC::REDUCE_ALL, curLen);
            float localMax = maxScalar.GetValue(0);

            scalarQueue_.FreeTensor(maxScalar);
            inQueueX_.FreeTensor(xLocal);

            if (localMax > globalMax) globalMax = localMax;
        }
        return globalMax;
    }

    // Phase 2: Compute sum of exp(x - globalMax)
    __aicore__ inline float phase2ComputeSum(uint32_t rowOffset, uint32_t numTiles, float globalMax)
    {
        float globalSum = 0.0f;
        for (uint32_t t = 0; t < numTiles; ++t) {
            const uint32_t tileBase = rowOffset + t * tileLen_;
            const uint32_t curLen = (tileLen_ > (rowLen_ - t * tileLen_)) ? (rowLen_ - t * tileLen_) : tileLen_;
            if (curLen == 0) break;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[tileBase], curLen);

            // exp(x - globalMax)
            AscendC::LocalTensor<float> subLocal = tmpQueue_.AllocTensor<float>();
            AscendC::Sub(subLocal, xLocal, globalMax, curLen);
            AscendC::Exp(subLocal, subLocal, curLen);

            // Local sum
            AscendC::LocalTensor<float> sumScalar = scalarQueue_.AllocTensor<float>();
            AscendC::ReduceSum(sumScalar, subLocal, AscendC::REDUCE_ALL, curLen);
            float localSum = sumScalar.GetValue(0);
            globalSum += localSum;

            scalarQueue_.FreeTensor(sumScalar);
            tmpQueue_.FreeTensor(subLocal);
            inQueueX_.FreeTensor(xLocal);
        }
        return globalSum;
    }

    // Phase 3: Normalize to produce final output.
    __aicore__ inline void phase3Normalize(uint32_t rowOffset, uint32_t numTiles, float globalMax, float globalSum)
    {
        for (uint32_t t = 0; t < numTiles; ++t) {
            const uint32_t tileBase = rowOffset + t * tileLen_;
            const uint32_t curLen = (tileLen_ > (rowLen_ - t * tileLen_)) ? (rowLen_ - t * tileLen_) : tileLen_;
            if (curLen == 0) break;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[tileBase], curLen);

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            // y = (x - globalMax)
            AscendC::Sub(yLocal, xLocal, globalMax, curLen);
            // exp(y)
            AscendC::Exp(yLocal, yLocal, curLen);
            // y = y / globalSum
            AscendC::Div(yLocal, yLocal, globalSum, curLen);

            AscendC::DataCopy(yGm_[tileBase], yLocal, curLen);

            inQueueX_.FreeTensor(xLocal);
            outQueueY_.FreeTensor(yLocal);
        }
    }

    __aicore__ inline void processRow(uint32_t rowIdx)
    {
        const uint32_t rowOffset = rowIdx * rowLen_;
        const uint32_t numTiles = (rowLen_ + tileLen_ - 1) / tileLen_;

        float globalMax = phase1FindMax(rowOffset, numTiles);
        float globalSum = phase2ComputeSum(rowOffset, numTiles, globalMax);

        // Avoid division by zero
        if (globalSum < 1e-30f) globalSum = 1e-30f;

        phase3Normalize(rowOffset, numTiles, globalMax, globalSum);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, SCALAR_BUF_NUM> scalarQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t rowLen_ {0};
    uint32_t numRows_ {0};
};

extern "C" __global__ __aicore__ void softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.blockDim, tiling_data.rowLength);
    op.Process();
}
